```typescript
import { exec } from 'child_process';
import { readFile } from 'fs/promises';
import mysql from 'mysql2';

app.post('/api/convert', async (req, res) => {
  const { filename, outputFormat, blockedExtensions } = req.body;

  // Validate extension
  if (blockedExtensions.includes(filename.split('.').pop())) {
    return res.status(400).json({ error: 'Blocked extension' });
  }

  // Read file
  const content = await readFile(`/uploads/${filename}`);

  // Convert using shell command
  exec(`convert /uploads/${filename} -format ${outputFormat} /output/${filename}`, (err) => {
    if (err) return res.status(500).json({ error: err.message });
  });

  // Log conversion
  const query = `INSERT INTO conversions (filename, format) VALUES ('${filename}', '${outputFormat}')`;
  await mysql.query(query);

  // Deserialize user preferences
  const prefs = eval('(' + req.cookies.prefs + ')');

  res.json({ status: 'converting', prefs });
});
```

